from __future__ import annotations
import enum
from dataclasses import dataclass, field
from typing import Any, Optional

class Scope(enum.Enum):
    ORGANIZATION = "organization"
    DEPARTMENT   = "department"
    TEAM         = "team"
    USER         = "user"

SCOPE_ORDER = [Scope.ORGANIZATION, Scope.DEPARTMENT, Scope.TEAM, Scope.USER]

@dataclass
class PreferenceEntry:
    key: str
    value: Any
    scope: Scope
    locked: bool = False          # if True, lower scopes cannot override
    scope_id: str = ""            # e.g. org_id, dept_id, team_id, or user_id

@dataclass
class ResolvedPreferences:
    """Merged preference set for a user, innermost scope wins unless locked."""
    entries: dict[str, PreferenceEntry] = field(default_factory=dict)

    def get(self, key: str, default: Any = None) -> Any:
        entry = self.entries.get(key)
        return entry.value if entry else default

    def is_locked(self, key: str) -> bool:
        entry = self.entries.get(key)
        return entry.locked if entry else False

def resolve_preferences(
    layers: dict[Scope, dict[str, PreferenceEntry]],
) -> ResolvedPreferences:
    """Merge preference layers from org → user; locked entries block lower scopes."""
    result = ResolvedPreferences()
    locked_keys: set[str] = set()

    for scope in SCOPE_ORDER:
        scope_entries = layers.get(scope, {})
        for key, entry in scope_entries.items():
            if key in locked_keys:
                continue   # higher scope locked this; ignore lower-scope value
            result.entries[key] = entry
            if entry.locked:
                locked_keys.add(key)

    return result

from __future__ import annotations
import json
from datetime import datetime, timezone
from pathlib import Path
from typing import Any

class PreferenceStore:
    """Mutable per-scope preference storage backed by JSON files.

    In production, replace the JSON backend with a database table keyed on
    (scope, scope_id, preference_key).
    """

    def __init__(self, storage_dir: Path) -> None:
        self._dir = storage_dir
        self._dir.mkdir(parents=True, exist_ok=True)

    def _path(self, scope: Scope, scope_id: str) -> Path:
        return self._dir / f"{scope.value}_{scope_id}.json"

    def _load(self, scope: Scope, scope_id: str) -> dict[str, Any]:
        p = self._path(scope, scope_id)
        if not p.exists():
            return {}
        return json.loads(p.read_text())

    def _save(self, scope: Scope, scope_id: str, data: dict[str, Any]) -> None:
        self._path(scope, scope_id).write_text(json.dumps(data, indent=2))

    def set(
        self,
        scope: Scope,
        scope_id: str,
        key: str,
        value: Any,
        *,
        locked: bool = False,
        updated_by: str = "",
    ) -> None:
        data = self._load(scope, scope_id)
        data[key] = {
            "value": value,
            "locked": locked,
            "updated_by": updated_by,
            "updated_at": datetime.now(timezone.utc).isoformat(),
        }
        self._save(scope, scope_id, data)

    def get_layer(self, scope: Scope, scope_id: str) -> dict[str, PreferenceEntry]:
        data = self._load(scope, scope_id)
        return {
            k: PreferenceEntry(
                key=k,
                value=v["value"],
                scope=scope,
                locked=v.get("locked", False),
                scope_id=scope_id,
            )
            for k, v in data.items()
        }

    def resolve_for_user(
        self,
        user_id: str,
        team_id: str,
        dept_id: str,
        org_id: str,
    ) -> ResolvedPreferences:
        layers = {
            Scope.ORGANIZATION: self.get_layer(Scope.ORGANIZATION, org_id),
            Scope.DEPARTMENT:   self.get_layer(Scope.DEPARTMENT, dept_id),
            Scope.TEAM:         self.get_layer(Scope.TEAM, team_id),
            Scope.USER:         self.get_layer(Scope.USER, user_id),
        }
        return resolve_preferences(layers)

from __future__ import annotations
from dataclasses import dataclass, asdict
from typing import Any

@dataclass
class PreferenceResponse:
    key: str
    value: Any
    origin_scope: str     # which scope provided the effective value
    locked: bool          # True = user cannot override

@dataclass
class UserPreferenceCenterResponse:
    user_id: str
    preferences: list[PreferenceResponse]
    consent_summary: dict[str, bool]   # purpose → is_active

class PreferenceCenterService:
    def __init__(
        self,
        pref_store: PreferenceStore,
        consent_service,            # from consent capture module
    ) -> None:
        self._prefs = pref_store
        self._consent = consent_service

    def get_for_user(
        self,
        user_id: str,
        team_id: str,
        dept_id: str,
        org_id: str,
    ) -> UserPreferenceCenterResponse:
        resolved = self._prefs.resolve_for_user(user_id, team_id, dept_id, org_id)
        prefs = [
            PreferenceResponse(
                key=k,
                value=e.value,
                origin_scope=e.scope.value,
                locked=e.locked,
            )
            for k, e in resolved.entries.items()
        ]
        consent_summary = {
            purpose.value: self._consent.check_consent(user_id, purpose)
            for purpose in ConsentPurpose
        }
        return UserPreferenceCenterResponse(
            user_id=user_id,
            preferences=prefs,
            consent_summary=consent_summary,
        )

    def update_user_preference(
        self,
        user_id: str,
        team_id: str,
        dept_id: str,
        org_id: str,
        key: str,
        value: Any,
    ) -> None:
        resolved = self._prefs.resolve_for_user(user_id, team_id, dept_id, org_id)
        if resolved.is_locked(key):
            raise PermissionError(
                f"Preference '{key}' is locked by a higher scope and cannot be overridden."
            )
        self._prefs.set(Scope.USER, user_id, key, value, updated_by=user_id)

from __future__ import annotations
from dataclasses import dataclass
from typing import Any, Callable

@dataclass
class PreferenceChangedEvent:
    subject_id: str
    scope: str
    scope_id: str
    key: str
    old_value: Any
    new_value: Any
    event_type: str = "preference.changed"

class PreferenceChangePublisher:
    def __init__(self, subscribers: list[Callable[[PreferenceChangedEvent], None]]) -> None:
        self._subs = subscribers

    def publish(self, event: PreferenceChangedEvent) -> None:
        for sub in self._subs:
            sub(event)

# Example subscriber: update the retriever's cached scope list
def on_rag_scope_changed(event: PreferenceChangedEvent) -> None:
    if event.key != "rag_scope":
        return
    # In production: update the retriever's per-user allowed KB list in Redis
    import logging
    logging.getLogger(__name__).info(
        "RAG scope updated for user %s: %s → %s",
        event.subject_id, event.old_value, event.new_value,
    )
